var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"07:30 AM 전략특수전사령부 휘하 <color=#ffd34c>제 7 델타분견대</color> \\n통칭 <color=#ffd34c>델타 세븐</color> 기함 <color=#ffd34c>뉴 오하이오 작전실</color>      ","JPN":"07:30 AM 戦略特殊戦司令部所属<color=#ffd34c>第7デルタセブン支隊</color>\\n通称<color=#ffd34c>デルタセブン</color>艦船<color=#ffd34c>ニューオハイオ作戦室</color>     ","ENG":"7:30 a.m., Strategic Special Operations Command, <color=#ffd34c>7th Delta Detachment</color>\\nA.K.A. <color=#ffd34c>Delta Seven</color> Flagship <color=#ffd34c>New Ohio Strategy Room</color>      ","TWN":"07:30 AM 戰略特戰司令部指揮所屬 <color=#ffd34c>第七三角洲分遣隊</color> \\n通稱 <color=#ffd34c>第七三角洲</color> 司令艦 <color=#ffd34c>新俄亥俄作戰室</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"마리아 안토노프, 카일 웡, 실비아 레나 쿠퍼 \\n<color=#ffd34c>CSE Level 1</color>","JPN":"マリア・アントノフ、カイル・ウォン、シルビア・レナ・クーパー\\n<color=#ffd34c>CSE Level 1</color>","ENG":"Maria Antonov, Kyle Wong, Sylvia Lena Cooper\\n<color=#ffd34c>CSE Level 1</color>","TWN":"瑪麗亞． 安東諾夫，希爾維亞． 蕾娜．庫博 \\n<color=#ffd34c>CSE Level 1</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다들 모였나? 작전 브리핑을 시작하려고 하는데.","JPN":"全員集まったか？　作戦のブリーフィングを始めたいのだが。","ENG":"Is everyone here? I want to start the operation briefing.","TWN":"大家都到齊了？我要開始作戰簡要說明了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하암...... 마리아 아줌마, 뭐 이런 꼭두새벽부터 사람을 오라 가라 그래?","JPN":"ふあ～マリアおばさん、こんな朝っぱらから集まる必要あるの？","ENG":"*Yawn* Maria, did you really have to wake me up so early in the morning?","TWN":"（哈欠）哈啊……瑪麗亞大嬸，幹嘛大清早就把人叫來啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"소장님께 말버릇이 그게 뭡니까! 실비아씨.","JPN":"少将に対し、なんて失礼な言い方を！　シルビアさん。","ENG":"Sylvia, you're speaking to the Major General.","TWN":"你這是和少將說話的口氣嗎！希爾維亞小姐。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 오전 7시면 일반인들도 충분히 활동을 시작할 시간입니다. 새벽이 아니에요!","JPN":"それに、午前7時は一般人が普通に活動を始める時間帯ですよ。\\n朝っぱらだなんて！　","ENG":"And 7 a.m. is not that early. Most people start their day around this time.","TWN":"而且早上7點一般人早就開始活動，不是大清早了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐래? 난 11시 기상 새벽 4시 취침이 디폴트거든.","JPN":"関係ないし。\\nアタシは11時に起きて、夜中の4時に寝るのがフツーなのよ。","ENG":"Not me. I wake up at 11 a.m. and go to bed at 4 a.m.","TWN":"你說什麼？早上11點起床淩晨四點就寢才是我的日常。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨의 개인적인 활동 선호시간 따위는 전혀 궁금하지 않습니다.","JPN":"シルビアさんの個人的な活動時間なんてまったく興味ありません。","ENG":"No one's interested in your personal daily routine, Sylvia.","TWN":"我對希爾維亞小姐個人的活動時間偏好沒有興趣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이제 실비아씨도 부대의 일원이 된 이상 규율과 규칙의 엄정함을 존중하는 태도를 가져야 합니다.","JPN":"シルビアさんも部隊の一員になった以上、\\n厳正な規律と規則を尊重するべきです。","ENG":"Now that you're a member of this unit, you must follow its rules and regulations like everyone else.","TWN":"但既然希爾維亞小姐現在也成為了部隊的一員，就必須尊重紀律與規則的嚴正性。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"난 너랑 다르게 <color=#ffd34c>민간직</color> 군사 협조 요원이라서 말이야.","JPN":"アタシは君と違って、<color=#ffd34c>民間</color>の軍事協力要員なの。","ENG":"But unlike you, I'm a <color=#ffd34c>civilian</color> collaborator.","TWN":"因為我和你不一樣，是<color=#ffd34c>民間</color>軍事協助要員啊，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내 개인적인 <color=#ffd34c>엄정한</color> 규율에 착실히 따르고 있으니까 신경 좀 꺼줄래?","JPN":"独自の<color=#ffd34c>厳正な</color>規律を順守してるんだから、茶々入れないでくれる？","ENG":"And I'm following <color=#ffd34c>rules</color> of my own, so get off my back, will you?","TWN":"我會確實遵守自己<color=#ffd34c>嚴肅的</color>紀律，可以不要囉嗦我的事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어쩔 수 없군요. 저도 이런 방법은 쓰고 싶지 않았지만......","JPN":"仕方ないですね。僕もこんなやり方は避けたかったのですが……","ENG":"Fine. I really didn't want to do this,","TWN":"沒辦法。我也不太想用這種手段，不過……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건 다 실비아 씨가 자초한 일이니 그렇게 아십시오.","JPN":"すべてシルビアさん自ら招いたことですから、ご承知おきを。","ENG":"but you're leaving me little choice, Sylvia.","TWN":"請希爾維亞小姐知道，這都是妳自找的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 무슨 짓을 하려고......","JPN":"え？　何をするつもり……","ENG":"What? What are you trying to—","TWN":"什麼？你想做什……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>경고!</color>","JPN":"<color=#ffd34c>警告！</color>","ENG":"<color=#ffd34c>Warning!</color>","TWN":"<color=#ffd34c>警告！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ONLY_KYLE_WALL_DAMAGE_DOWN"},{"id":"L20_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>강제 권한 개입에 의해 임시적으로 작동을 정지합니다.</color>","JPN":"<color=#ffd34c>強制措置により、作動を一時停止します。</color>","ENG":"<color=#ffd34c>The system's operation has been temporarily put to a halt by forced intervention.</color>","TWN":"<color=#ffd34c>由於強制權限干涉，暫時終止運作。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ONLY_KYLE_WALL_DAMAGE_DOWN"},{"id":"L21_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모든 시스템이 동결되었습니다. 재기동 절차에 대해서는 권한자에게 문의하십시오.</color>","JPN":"<color=#ffd34c>すべてのシステムが凍結されました。\\n再起動の手順は権限者にお問い合わせください。</color>","ENG":"<color=#ffd34c>It is now inactive. For its reactivation process, please inquire with the administrator.</color>","TWN":"<color=#ffd34c>所有系統都被凍結。請向權限所有者諮詢重新開機步驟。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_TOTEM_DAMAGE_DOWN"},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......어? ......어?!!","JPN":"……え？　……ええ！！？","ENG":"What? WHAT?!","TWN":"……什麼？……什麼？！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"야! 너 무슨 짓을 한 거야? 내 리프노드를 어떻게 정지시킨 건데?!!","JPN":"君！　なんのマネなの？\\nアタシのリーフノードをどうやって停止させたわけ！？","ENG":"Hey, what did you do? How did you stop my Leaf Node?!","TWN":"喂！你做了什麼？你是怎麼終止我的節點的？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그 전자전 드론의 설계자는 실비아 씨이지만 부품은 델타 세븐의 예산으로 조달했다는 사실을 잊지 마십시오.","JPN":"その電子戦ドローンの設計者はシルビアさんですが、\\n部品はデルタセブンの予算で調達したということをお忘れなく。","ENG":"You may have designed that electronic warfare drone, but its actual construction was funded by Delta Seven.","TWN":"雖然，這個電子戰無人機的設計者是希爾維亞小姐，但請不要忘了，採購零件用的是第七三角洲部隊的預算。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨가 지금처럼 규칙을 존중하지 않을 경우 리프노드의 통제권을 강제 회수할 수 있는 모종의 시스템이 탑재되어 있습니다.","JPN":"シルビアさんが今回のように規則を順守しない場合、\\nリーフノードの操作権限を強制奪取できるシステムが搭載されています。","ENG":"It's embedded with a system to rescind your ability to control it in case you refuse to follow rules, just like right now.","TWN":"如果希爾維亞小姐像現在這樣不尊重紀律，上面裝載了某種系統就會強制收回節點的控制權。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なんですって？","ENG":"W-what?","TWN":"你、你說什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그럴 리가 없어! 리프노드에 탑재된 코드는 따옴표 하나까지 내가 다 검수했다고!","JPN":"そんなはずないわ！　リーフノード搭載コードはクォーテーションマークの一つまで\\nすべてアタシが検収したもの！","ENG":"No way! I know every single code embedded in Leaf Node's system. I've checked them all!","TWN":"怎麼可能！節點上裝載的代碼，就連雙引號我都全部檢查過！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 아니면 내 눈을 속이고 백도어를 삽입했다고......? 설마......","JPN":"そ、それとも、私の目を盗んでバックドアを組み込んだとか……？\\nまさかそんな……","ENG":"A-are you telling me you've slipped in a backdoor without my knowledge? No...","TWN":"還、還是你瞞著我，在裡面插入了什麼後門程式？不會吧……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"안심하시죠. 실비아씨의 품행과는 달리 해킹 실력에 대해서는 인정하고 있으니까요.","JPN":"ご安心を。シルビアさんの品行評価とは関係なく、\\nハッキング能力については認めていますから。","ENG":"Don't worry. I may not approve of you as a person, but I do know how good of a hacker you are.","TWN":"放心吧。不同於希爾維亞小姐的態度，妳的駭客實力我們都是認可的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"애초에 제 능력으로 백도어를 심는 게 가능했다면 실비아씨는 당장 해고당했을 겁니다.","JPN":"そもそも僕がバックドアを組み込むことができる程度なら、\\nシルビアさんは即クビだったでしょうね。","ENG":"If you were so incompetent that you let me plant a backdoor in it, you would have been let go a long time ago.","TWN":"如果憑我的能力能在節點中藏入後門程式，那希爾維亞小姐早就被解雇了吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건 주 연산회로에 통합되어 있는 하드웨어적 장치에 내장되어 있는 기능입니다.","JPN":"これはコア演算回路に統合されているハードウェア内蔵の機能。","ENG":"This function is installed in a hardware device integrated to the drone's main circuit.","TWN":"這個功能內藏在整合主運算電路的硬體裝置上。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"단순하지만 효과적이죠. 그러니 앞으로도 그 드론을 빼앗기고 싶지 않으시면,","JPN":"シンプルながら効果的な機能です。\\nですから、今後もそのドローンを奪われたくないなら","ENG":"It's simple, but effective. So, if you don't want to lose your drone,","TWN":"很簡單但也很有效吧。所以希爾維亞小姐如果不希望以後再被奪走控制權……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨도 규칙을 존중하는 자세를 가져야 할 겁니다.","JPN":"シルビアさんも規則を守ったほうが良いでしょうね。","ENG":"you'd better follow the rules.","TWN":"就必須保持尊重規則的態度。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......공부 안 하면 휴대폰 뺏어가겠다는 엄마랑 비슷한 소리를 하네.","JPN":"……まるで、勉強しないならスマホ没収ってママに言われてるみたい。","ENG":"You sound like a mother who's threatening to take away her daughter's cell phone if she doesn't study hard enough.","TWN":"……你這話聽起來，就好像哪個媽媽在說如果你不好好念書，就沒收你的手機呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"너 애늙은이라는 소리 듣지 않냐?","JPN":"君、年齢のわりに堅物だって言われない？","ENG":"People say you act like an old man, don't they?","TWN":"你有聽過什麼叫小老頭嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제 철저한 자기관리에 대한 칭찬으로 듣겠습니다.","JPN":"徹底した自己管理への褒め言葉だと解釈します。","ENG":"I'll take that as a compliment for my exceptional self-control.","TWN":"我就當作妳是在稱讚我嚴格的自我管理了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 네...... 그러시겠죠.","JPN":"あっそう……そうでしょうね。","ENG":"Yeah, yeah. You do that.","TWN":"啊，是喔……說得也是。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"인사는 끝났나, 카일, 실비아?","JPN":"挨拶は終わったかな、カイル、シルビア？","ENG":"Kyle. Sylvia. Are you done greeting each other?","TWN":"招呼打完了嗎，凱爾、希爾維亞？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 아직 한 명이 안 보이는군.","JPN":"まだ一人いないな。","ENG":"We're still short one person.","TWN":"話說回來，還有一個人我沒有看到呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"보고가 늦어서 죄송합니다, 소장님.","JPN":"報告が遅れて申し訳ありません、少将。","ENG":"I'm sorry I couldn't tell you this earlier, Major General.","TWN":"我報告遲了，非常抱歉，少將大人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제이크 소령님은 어제 저녁부터 연락이 두절된 상태입니다.","JPN":"ジェイク少佐は昨夜から音信不通の状況です。","ENG":"I haven't heard from Major Walker since last night.","TWN":"傑克少校從昨晚開始就處於失聯狀態。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"함선 및 지상기지 내에서 모습을 찾아볼 수 없는 걸 보면 아마도 평소처럼......","JPN":"艦船および地上基地内でも見当たらないので、おそらくいつも通り……","ENG":"I haven't seen him in the ship or the land base, either. He's probably...","TWN":"在艦船及地上基地內都找不到他，大概像平時那樣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"여어~ 꼬맹이 전우 여러분! 벌써 다들 모여 계시는군.","JPN":"やあ、チビッ子の戦友たち！","ENG":"Hey, my fellow comrades! Everyone's here already.","TWN":"喲～各位小矮子戰友們！大家都已經集合啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"내가 좀 늦었지? 일찍 들어오려고 했는데 워낙 붙잡는 아가씨들이 많아서 말이야.","JPN":"少し遅れてしまったかな？\\n急ぐつもりだったんだが、女性陣がなかなか離してくれなくってね。","ENG":"Sorry I'm late. I wanted to come back early, but the ladies wouldn't let me.","TWN":"我是不是來得有點兒晚了？我本來想早點來的，但都是因為有好多小妞挽留我啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"소령님!","JPN":"少佐！","ENG":"Major!","TWN":"少校！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아무리 소령님이라고 해도 사적인 용무로 소장님의 호출에 늦는 건 중대한 규율 위반입니다!","JPN":"いくら少佐でも、プライベートな理由で少将の呼び出しに遅れるのは\\n重大な規律違反ですよ！","ENG":"It's a serious violation of rules not to show up for the Major General's summons on time, no matter what the reason. Even you're not an exception.","TWN":"就算您是少校，但因為私事延誤少將的呼叫是嚴重違反紀律的！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그보다 뭡니까? 이 술 냄새는!","JPN":"それより何です、この酒の匂いは！","ENG":"By the way, why do you smell like alcohol?","TWN":"而且這是什麼？一身的酒臭味！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"미안, 미안. 좀 봐달라고.","JPN":"わりぃわりぃ、大目に見てくれ。","ENG":"Sorry, sorry. Cut me some slack, will you?","TWN":"抱歉，抱歉。你就饒我一次嘛。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그냥 인사치레만 했는데 클럽에서 나오니까 벌써 새벽이지 뭐야?","JPN":"ちょっとだけ挨拶回りしただけなのに、\\nクラブから出てみたらもう夜が明けているじゃねえか。","ENG":"I only went in to the club to say hello to some dudes, and by the time I left it, it was already morning.","TWN":"我只是去客套一下而已，誰知道一出酒吧，就已經清晨啦？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"소장님께도 죄~ 송합니다.","JPN":"少将もすみませ～ん。","ENG":"My apologies to you too, Major General.","TWN":"對少將大人也非～常抱歉啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"소령님!!","JPN":"少佐！！","ENG":"Major!","TWN":"少校大人！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮아, 카일. 개인사에는 관여하지 않는 게 내 지휘방식이니까.","JPN":"いいんだ、カイル。\\nプライベートには関与しないのが私の指揮スタイルだからな。","ENG":"It's okay, Kyle. I don't care what he does in his own private time, so long as he follows my commands.","TWN":"沒關係，凱爾。畢竟我的指揮方式向來不干涉私事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"얼른 자리에나 가서 앉게.","JPN":"それより、早く席についてくれたまえ。","ENG":"Just go have a seat.","TWN":"快坐到位子上吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 역시 우리 소장님은 마음도 넓으시다니까요.","JPN":"ハハ、さすがうちの少将は心が広い。","ENG":"Hah hah. My Major General is so generous!","TWN":"哈哈，果然我們少將大人心胸寬廣啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"끄응......","JPN":"ぐぬぬ……","ENG":"*Groan*","TWN":"唔……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다들 모였으니 브리핑을 시작하지.","JPN":"全員集まったな。ブリーフィングを始めよう。","ENG":"Now that everyone's here, let me start the briefing.","TWN":"既然大家都到了，我就開始任務說明了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"오늘 우리는 언제나처럼 전술 평가작전을 진행할 예정이다.","JPN":"本日、我々はいつも通り戦術評価作戦を遂行する予定だ。","ENG":"Today, we'll be carrying out a tactical evaluation, as always.","TWN":"今天我們將和以往一樣，預計進行戰術評估作戰。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"본 함, 뉴 오하이오에 탑승하여 목표좌표의 이면세계로 다이브한다.","JPN":"本艦ニューオハイオに搭乗し、目標座標の裏世界にダイブする。","ENG":"We'll take this ship, New Ohio, and dive into the preselected coordinates in the Counterside.","TWN":"乘坐本艦新俄亥俄，躍入到異界的目的地座標……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 곳에서 미리 대기하고 있던 정보부 파견대와 접선하여 그들이 임무를 수행하는 동안 주변 침식체들을 요격하는 것이 우리의 주 임무다.","JPN":"そして、あらかじめ待機している情報局の支隊と接触。\\n彼らが任務を遂行している間、周辺の侵食体を迎撃するのが我々の主な任務だ。","ENG":"Our objective is to make contact with the Intelligence Agency's detached force that's already there, and keep C.O.s away from it while it's carrying out its mission.","TWN":"然後和在那裡待命的情報部派遣隊會合。我們的主要任務，就是在他們執行任務時迎擊周圍的侵蝕體。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"혹시나 해서 물어보는 건데, 한 명이 안 보이는걸?","JPN":"念のため聞いておくけど、一人足りないんじゃない？","ENG":"In case you didn't notice, we're still missing one person.","TWN":"以防萬一問一下，還有一個人沒到吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정보부 뒤치다꺼리나 하는 임무라는 거 보니까 이번에도......","JPN":"情報局の雑用係的な任務っていうことは、今回もやっぱり……","ENG":"Since we're going to be cleaning up after the Intelligence Agency, he's probably—","TWN":"說是給情報部善後的任務，看來這次也……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉 킹 레지날드 준장은 정보부 파견대 지휘관으로, 현장에서 합류할 예정이다.","JPN":"ドミニーク・キング・レジナルド准将は、\\n情報局の支隊指揮官として現場で合流する予定だ。","ENG":"Brigadier General Dominic King Reginald will join us at the site, as the commander of the Intelligence Agency's detached force.","TWN":"多明尼克·金·雷吉納德准將是情報部派遣隊的指揮官，他會在現場與我們會合。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어이, 카일. 뭐 할 말 없냐?","JPN":"おい、カイル。何か言うことないか？","ENG":"Hey, Kyle. Don't you have anything to say about that?","TWN":"喂，凱爾，你沒什麼要說的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"불만이 없진 않지만...... 전 소장님의 명령이라면 따를 뿐입니다.","JPN":"不満がないわけではないですが……僕は少将命令なら従うのみです。","ENG":"I can't say I'm happy, but I'll follow the Major General's orders, no matter what.","TWN":"雖然並非沒有不滿……但只要是少將大人的命令，我都會遵從。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......군인 정신 투철하네.","JPN":"……さすが、根っからの軍人気質だな。","ENG":"You're a soldier through and through.","TWN":"……完全貫徹軍人精神呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 마리아 아줌마! 그 사람은 대체 무슨 생각인 거야?!","JPN":"ちょっとマリアおばさん！　あの人、いったいどういうつもりなの！？","ENG":"Hey, Maria. What the hell is he thinking?","TWN":"我說，瑪麗亞大嬸！那個人到底想什麼啊？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아무리 정보부로 이동이 내정됐다고 해도 아직은 우리 부사령관이잖아?","JPN":"情報局への異動が内定しているとはいえ、まだうちの副司令官でしょ？","ENG":"Even if his transfer to the Agency has been decided, he's still our deputy commander.","TWN":"就算已經內定轉去情報部，但他現在好歹還是我們的副司令官吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 대놓고 그쪽 부대 지휘를 맡으러 간 거야?","JPN":"なのに、こんな表立って向こうの指揮に従ってるわけ？","ENG":"How can he leave us to command their troops?","TWN":"結果他就大喇喇地指揮情報部隊去了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아주 난 정치장교라고 타임스퀘어에 광고라도 걸지 그래?","JPN":"自分は政治将校だと宣伝するようなもんじゃない。","ENG":"If he's so desperate to advertise his political prowess, perhaps he should buy a billboard in Time Square.","TWN":"真的是，他怎麼不去時代廣場掛個我是政治將領的廣告？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"와우, 이럴 때 앞뒤 안 가리고 막말을 직구로 꽂아 넣을 수 있는 건 역시 우리 실비아뿐이라니까.","JPN":"おお、こんな時にもお構いなしにド直球をぶちかますなんて、\\nさすがうちのシルビアだ。","ENG":"Wow, Sylvia! Only you could speak so honestly in a situation like this.","TWN":"哇啊，這種時候能夠口無遮攔地開罵的，果然就只有我們的希爾維亞了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하하, 도미닉이 조금 사교성이 떨어지는 편이긴 하지.","JPN":"ハハハ、ドミニークは少し社交性に欠けるところがあるのは事実だが。","ENG":"Hah hah. Dominic may not be the most sociable person you know.","TWN":"哈哈，多明尼克在社交方面確實有些不足。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 그 친구도 나름대로 국가와 인류를 위해 노력하고 있다네. 놀랍게도 말이야.","JPN":"あいつなりに国や人類のために尽くしているんだ、驚いたことにな。","ENG":"But he's working hard in his own right for his country and mankind, although you may not believe it.","TWN":"不過，那位朋友也在以自己的方式為國家和人類而努力啊，但確實是有些令人驚訝就是了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"오랫동안 같이 지내 온 내가 보증하는 평가니까 다들 너무 미워하지는 말았으면 좋겠어.","JPN":"長年付き合ってきた私が保証しよう。だから、みんなあまり憎まないでほしい。","ENG":"But I can vouch for him, because I've been with him for a long time. Don't hate him too much.","TWN":"我與他相識多年，這一點我還是可以保證的，所以希望大家不要太討厭他。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하아...... 아줌마가 그렇다면 뭐 어쩔 수 없지......","JPN":"はあ……おばさんにそう言われたら、仕方ないわ……","ENG":"*Sigh* Okay, if you say so.","TWN":"哈啊……大嬸這麼說了那也沒辦法……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이해해 주니 고맙군, 실비아.","JPN":"君の理解に感謝する、シルビア。","ENG":"Thank you for your understanding, Sylvia.","TWN":"謝謝妳能理解，希爾維亞。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 출발한다.","JPN":"では、出発だ。","ENG":"Now, let's go.","TWN":"那麼出發吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"접선 장소까지 도달하는 동안 다수의 침식체들과 조우할 것으로 예상되니까 다들 주의하도록.","JPN":"接触場所まで複数の侵食体に遭遇するだろう。\\nみんな、注意するように。","ENG":"There will be a lot of C.O.s on our way to the rendezvous point. Everyone, brace yourself.","TWN":"到達會合地點之前，我們預計會遭遇很多侵蝕體，請各位做好準備。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};